"use client";

import { useEffect, useState } from "react";
import { Mail, User, ArrowLeft, Clock, Inbox, ShieldCheck } from "lucide-react";
import { useRouter } from "next/navigation";

const BASE_URL = "http://localhost:5000";

const MyMessagesPage = () => {
  const router = useRouter();
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchMessages = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/user/myMessage`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to fetch messages");
        const data = await res.json();
        setMessages(data);
      } catch (err) {
        console.error("Message fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchMessages();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-[#F8FAFC] flex flex-col items-center justify-center">
        <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-500 font-medium animate-pulse">
          Checking your inbox...
        </p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] pb-20">
      {/* Header */}
      <div className="bg-white border-b border-slate-200 sticky top-0 z-20">
        <div className="max-w-4xl mx-auto px-6 py-5 flex items-center justify-between">
          <button
            onClick={() => router.back()}
            className="group flex items-center text-slate-500 hover:text-indigo-600 transition-colors"
          >
            <ArrowLeft
              size={18}
              className="mr-2 group-hover:-translate-x-1 transition-transform"
            />
            <span className="text-sm font-semibold uppercase tracking-wider">
              Back
            </span>
          </button>
          <div className="flex items-center gap-2">
            <div className="p-2 bg-indigo-50 rounded-lg">
              <Mail size={20} className="text-indigo-600" />
            </div>
            <h1 className="text-lg font-bold text-slate-900 tracking-tight">
              Notification Center
            </h1>
          </div>
          <div className="w-16"></div> {/* Spacer for balance */}
        </div>
      </div>

      <main className="max-w-4xl mx-auto px-6 mt-10">
        {/* Welcome Text */}
        <div className="mb-8">
          <h2 className="text-2xl font-black text-slate-900">Your Messages</h2>
          <p className="text-slate-500 text-sm mt-1">
            Updates regarding your claims and account activity.
          </p>
        </div>

        {messages.length === 0 ? (
          <div className="bg-white rounded-3xl border border-slate-200 p-16 text-center flex flex-col items-center shadow-sm">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
              <Inbox size={40} className="text-slate-300" />
            </div>
            <h3 className="text-slate-900 font-bold text-lg">Inbox is empty</h3>
            <p className="text-slate-500 text-sm max-w-xs mt-2">
              When you receive updates about your lost items or claims, they
              will appear here.
            </p>
          </div>
        ) : (
          <div className="space-y-6">
            {messages.map((msg) => (
              <div
                key={msg._id}
                className="bg-white border border-slate-200 rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-shadow group"
              >
                <div className="p-6">
                  <div className="flex items-start justify-between">
                    {/* Sender Info */}
                    <div className="flex items-center gap-4">
                      <div className="relative">
                        <div className="w-12 h-12 rounded-xl bg-slate-900 text-white flex items-center justify-center font-bold text-lg shadow-inner">
                          {msg.sender?.name?.charAt(0) || "S"}
                        </div>
                        <div className="absolute -bottom-1 -right-1 bg-emerald-500 border-2 border-white w-4 h-4 rounded-full"></div>
                      </div>

                      <div>
                        <div className="flex items-center gap-2">
                          <p className="font-bold text-slate-900">
                            {msg.sender?.name || "System Administrator"}
                          </p>
                          {(!msg.sender || msg.sender.role === "admin") && (
                            <ShieldCheck
                              size={14}
                              className="text-indigo-500"
                            />
                          )}
                        </div>
                        <p className="text-xs text-slate-400 font-medium">
                          {msg.sender?.email || "automated@system.com"}
                        </p>
                      </div>
                    </div>

                    {/* Timestamp */}
                    <div className="flex items-center gap-1.5 text-slate-400">
                      <Clock size={14} />
                      <p className="text-[11px] font-bold uppercase tracking-tighter">
                        {new Date(msg.createdAt).toLocaleDateString(undefined, {
                          month: "short",
                          day: "numeric",
                        })}{" "}
                        •{" "}
                        {new Date(msg.createdAt).toLocaleTimeString([], {
                          hour: "2-digit",
                          minute: "2-digit",
                        })}
                      </p>
                    </div>
                  </div>

                  {/* Message Body */}
                  <div className="mt-6 relative">
                    <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-50 rounded-full group-hover:bg-indigo-500 transition-colors"></div>
                    <div className="pl-6">
                      <p className="text-slate-700 text-sm leading-relaxed whitespace-pre-line">
                        {msg.message}
                      </p>
                    </div>
                  </div>
                </div>

                {/* Optional Footer Action */}
                <div className="bg-slate-50 px-6 py-3 border-t border-slate-100 flex justify-end">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Message Ref: {msg._id.slice(-8)}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default MyMessagesPage;
